// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	// STRY0100152 
	if(isLoading){
		setDaysMessage(newValue);
		return;
	}

	setDaysMessage();
	function setDaysMessage(newValue){

		// STRY0091294
		var isSuspenseDateRequired = g_scratchpad.isSuspenseDateRequired;
		g_form.setMandatory('u_duration_days',isSuspenseDateRequired == 'true'); // To make mandatory


		g_form.showFieldMsg('u_duration_days', getMessage('Business Days needed for completion and sets the {0}').replace('{0}',g_scratchpad.suspense_date_label), 'info', false); 		
	}
}
